import React, { useMemo, useState } from "react";

import LaunchesTab from "./components/crm/LaunchesTab";
import ChannelsTab from "./components/crm/ChannelsTab";
import CalendarTab from "./components/crm/CalendarTab";
import BusinessRequirementsTab from "./components/crm/BusinessRequirementsTab";
import AssistantPanel from "./components/crm/AssistantPanel";
import ScheduleDraftModal from "./components/crm/ScheduleDraftModal";
import { ToastProvider, useToast } from "./components/crm/Toast";
import { useCRMStore } from "./lib/crm-store";
import {
  buildSchedule,
  downloadLaunchesTemplate,
  downloadRequirementsTemplate,
} from "./lib/planner-core";
import {
  getRequirementFingerprint,
  normalizeRequirement,
} from "./lib/requirements-domain";

const MASCOT_CALM =
  "data:image/jpeg;base64,";
const MASCOT_HAPPY =
  "data:image/jpeg;base64,";

function formatTodayLabel() {
  return new Intl.DateTimeFormat("ru-RU", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  }).format(new Date());
}

function AppInner() {
  const toast = useToast();
  const [activeTab, setActiveTab] = useState("launches");
  const [scheduleDraft, setScheduleDraft] = useState(null);
  const [assistantOpen, setAssistantOpen] = useState(false);
  const [mascotHover, setMascotHover] = useState(false);
  const [historyStack, setHistoryStack] = useState([]);

  const store = useCRMStore();
  const {
    launches,
    channels,
    requirements,
    messages,
    rules,
    preferences,
    addLaunch,
    updateLaunch,
    deleteLaunch,
    replaceLaunches,
    addChannel,
    updateChannel,
    deleteChannel,
    addRequirement,
    updateRequirement,
    deleteRequirement,
    setMessages,
    setRules,
    setPreferences,
  } = store;

  const todayLabel = useMemo(() => formatTodayLabel(), []);
  const activeRulesCount = useMemo(
    () => rules.filter((r) => r.status === "active").length,
    [rules]
  );

  // ── Undo ──
  function pushSnapshot() {
    setHistoryStack((prev) => [
      ...prev.slice(-9),
      launches.map((l) => ({ ...l })),
    ]);
  }
  function undoLastChange() {
    if (!historyStack.length) return;
    const prev = historyStack[historyStack.length - 1];
    replaceLaunches(prev.map((launch) => ({ ...launch })));
    setHistoryStack((s) => s.slice(0, -1));
    toast("Изменение отменено");
  }

  // ── Wrapped CRUD with toast ──
  function handleAddLaunch(launch) {
    pushSnapshot();
    addLaunch(launch);
    toast("Запуск добавлен");
  }
  function handleUpdateLaunch(launch) {
    pushSnapshot();
    updateLaunch(launch);
    toast("Запуск сохранён");
  }
  function handleDeleteLaunch(id) {
    pushSnapshot();
    deleteLaunch(id);
    toast("Запуск удалён");
  }
  function handleAddChannel(ch) {
    addChannel(ch);
    toast("Канал добавлен");
  }
  function handleUpdateChannel(ch) {
    updateChannel(ch);
    toast("Канал сохранён");
  }
  function handleDeleteChannel(id) {
    deleteChannel(id);
    toast("Канал удалён");
  }
  function handleAddRequirement(r) {
    addRequirement(r);
    toast("Требование добавлено");
  }
  function handleUpdateRequirement(r) {
    updateRequirement(r);
    toast("Требование сохранено");
  }
  function handleDeleteRequirement(id) {
    deleteRequirement(id);
    toast("Требование удалено");
  }

  function handleImportLaunches(imported) {
    pushSnapshot();
    imported.forEach((l) => addLaunch(l));
    toast("Импортировано " + imported.length + " запусков");
  }

  function handleResolveConflicts() {
    pushSnapshot();
    launches
      .filter((l) => l.conflictStatus === "conflict")
      .forEach((l) => {
        updateLaunch({ ...l, planningStatus: "бэклог" });
      });
    toast("Конфликтные запуски отправлены в бэклог");
  }

  function handleReset() {
    if (!window.confirm("Сбросить все запуски?")) return;
    pushSnapshot();
    replaceLaunches([]);
    toast("Данные сброшены");
  }

  // ── Schedule generation ──
  function handleGenerateSchedule() {
    if (requirements.length === 0) {
      toast(
        "Добавьте бизнес-требования во вкладке «Бизнес-требования»",
        "warn"
      );
      setActiveTab("business-requirements");
      return;
    }
    const result = buildSchedule({
      requirements,
      channels,
      rules,
      existingLaunches: launches,
    });
    if (result.proposed.length === 0) {
      toast(
        "Планировщик не нашёл подходящих слотов. Пропущено: " +
          result.skipped.length,
        "warn"
      );
    }
    setScheduleDraft(result);
  }

  async function handleDownloadLaunchesTemplate() {
    try {
      await downloadLaunchesTemplate();
      toast("Шаблон запусков скачан");
    } catch (error) {
      toast(
        error?.message || "Не удалось скачать шаблон запусков",
        "warn"
      );
    }
  }

  async function handleDownloadRequirementsTemplate() {
    try {
      await downloadRequirementsTemplate();
      toast("Шаблон бизнес-требований скачан");
    } catch (error) {
      toast(
        error?.message || "Не удалось скачать шаблон бизнес-требований",
        "warn"
      );
    }
  }

  function handleApplyAssistantActions(payload) {
    const actions = Array.isArray(payload?.actions) ? payload.actions : [];
    const nextRules = Array.isArray(payload?.rules) ? payload.rules : rules;
    const existingRequirementKeys = new Set(
      requirements.map((requirement) => getRequirementFingerprint(requirement))
    );

    const createdRequirements = actions
      .filter((action) => action.type === "create_requirement")
      .map((action) => action.payload?.requirement)
      .filter(Boolean)
      .map((requirement) => normalizeRequirement(requirement))
      .filter((requirement) => {
        const key = getRequirementFingerprint(requirement);
        if (existingRequirementKeys.has(key)) return false;
        existingRequirementKeys.add(key);
        return true;
      });

    createdRequirements.forEach((requirement) => addRequirement(requirement));

    let nextDraft = null;
    if (payload?.shouldRebuildSchedule && requirements.length + createdRequirements.length > 0) {
      const nextRequirements = [...requirements, ...createdRequirements];
      nextDraft = buildSchedule({
        requirements: nextRequirements,
        channels,
        rules: nextRules,
        existingLaunches: launches,
      });
      setScheduleDraft(nextDraft);
      if (nextDraft.proposed.length > 0) {
        setActiveTab("launches");
      }
    }

    return {
      createdRequirementsCount: createdRequirements.length,
      scheduleDraft: nextDraft,
    };
  }

  function handleConfirmDraft(accepted) {
    if (!accepted.length) {
      setScheduleDraft(null);
      return;
    }
    pushSnapshot();
    replaceLaunches([...launches, ...accepted]);
    setScheduleDraft(null);
    setActiveTab("launches");
    toast("Добавлено " + accepted.length + " запусков");
  }

  function handleApplyProposals(proposals) {
    if (!Array.isArray(proposals)) return;
    proposals.forEach((p) => {
      if (p.type === "create_new") {
        handleAddLaunch({
          id: "l-" + Date.now() + "-" + Math.random().toString(36).slice(2, 8),
          planningStatus: "бэклог",
          issues: [],
          conflictStatus: "ok",
          campaignType: "CRM акция",
          manager: "",
          ...p.suggested,
          game: p.game,
        });
      }
    });
  }

  function handleApplyDraft(actions) {
    if (!Array.isArray(actions)) return;
    actions.forEach((a) => {
      if (a.actionType === "create_new") {
        handleAddLaunch({
          id: "l-" + Date.now() + "-" + Math.random().toString(36).slice(2, 8),
          planningStatus: "бэклог",
          issues: [],
          conflictStatus: "ok",
          campaignType: "CRM акция",
          manager: "",
          ...a.suggested,
          game: a.game,
        });
      }
    });
  }

  return (
    <div className="app-bg">
      <style>{`
        @keyframes mascotFloat { 0%,100%{transform:translateY(0) rotate(-1deg)} 50%{transform:translateY(-7px) rotate(1deg)} }
        @keyframes mascotBounce { 0%,100%{transform:scale(1)} 40%{transform:scale(1.08) translateY(-6px)} 70%{transform:scale(0.97)} }
        @keyframes slideUp { from{opacity:0;transform:translateY(16px) scale(0.98)} to{opacity:1;transform:translateY(0) scale(1)} }
        .mascot-float { animation: mascotFloat 3.2s ease-in-out infinite; }
        .mascot-float:hover { animation: mascotBounce 0.55s ease-in-out; }
        .mascot-open { animation: none !important; transform: scale(0.93); }
      `}</style>

      <div className="container">
        <div
          className="hero"
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "flex-start",
            gap: "16px",
          }}
        >
          <div>
            <div className="title">CRM Timing Planner</div>
            <div
              style={{
                fontSize: "12px",
                color: "#71717a",
                marginTop: "4px",
                fontWeight: 500,
              }}
            >
              Тайминг актуален на {todayLabel}
            </div>
          </div>
          <div
            style={{
              display: "flex",
              gap: "8px",
              alignItems: "center",
              flexWrap: "wrap",
              marginTop: "4px",
            }}
          >
            {historyStack.length > 0 && (
              <button className="btn" onClick={undoLastChange}>
                Отменить
              </button>
            )}
            <button
              className="btn btn-primary"
              onClick={handleGenerateSchedule}
              style={{ letterSpacing: "-0.01em" }}
            >
              Сгенерировать тайминг
            </button>
          </div>
        </div>

        <div className="card">
          <div className="tabs">
            {[
              ["launches", "Запуски"],
              ["channels", "Каналы"],
              ["calendar", "Календарь"],
              ["business-requirements", "Бизнес-требования"],
            ].map(([id, label]) => (
              <button
                key={id}
                className={"tab" + (activeTab === id ? " tab-active" : "")}
                onClick={() => setActiveTab(id)}
              >
                {label}
              </button>
            ))}
          </div>

          {activeTab === "launches" && (
            <LaunchesTab
              channels={channels}
              launches={launches}
              assistantContext={{ messages, rules, preferences, toast }}
              onAddLaunch={handleAddLaunch}
              onUpdateLaunch={handleUpdateLaunch}
              onDeleteLaunch={handleDeleteLaunch}
              onApplyProposals={handleApplyProposals}
              onApplyDraft={handleApplyDraft}
              onImportLaunches={handleImportLaunches}
              onAutoResolve={handleResolveConflicts}
              onSuggestBetterSlot={() => null}
              onResetData={handleReset}
              onDownloadTemplate={handleDownloadLaunchesTemplate}
            />
          )}
          {activeTab === "channels" && (
            <ChannelsTab
              channels={channels}
              onAddChannel={handleAddChannel}
              onUpdateChannel={handleUpdateChannel}
              onDeleteChannel={handleDeleteChannel}
            />
          )}
          {activeTab === "calendar" && (
            <CalendarTab channels={channels} launches={launches} />
          )}
          {activeTab === "business-requirements" && (
            <BusinessRequirementsTab
              requirements={requirements}
              channels={channels}
              onAddRequirement={handleAddRequirement}
              onUpdateRequirement={handleUpdateRequirement}
              onDeleteRequirement={handleDeleteRequirement}
              onDownloadTemplate={handleDownloadRequirementsTemplate}
            />
          )}
        </div>
      </div>

      {/* Mascot */}
      <div
        style={{
          position: "fixed",
          bottom: "24px",
          right: "28px",
          zIndex: 300,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          gap: "8px",
          userSelect: "none",
        }}
      >
        {!assistantOpen && (
          <div
            style={{
              background: "#0a0a0a",
              color: "#fff",
              fontSize: "12px",
              fontWeight: 600,
              borderRadius: "8px",
              padding: "5px 10px",
              whiteSpace: "nowrap",
              opacity: mascotHover ? 1 : 0,
              transform: mascotHover ? "translateY(0)" : "translateY(4px)",
              transition: "opacity 0.16s,transform 0.16s",
              pointerEvents: "none",
              boxShadow: "0 4px 12px rgba(0,0,0,0.18)",
              letterSpacing: "-0.01em",
            }}
          >
            {"Ассистент"}
            {activeRulesCount > 0 ? ` · ${activeRulesCount} правил` : ""}
          </div>
        )}
        <div style={{ position: "relative" }}>
          <div
            className={assistantOpen ? "mascot-open" : "mascot-float"}
            onClick={() => setAssistantOpen((v) => !v)}
            onMouseEnter={() => setMascotHover(true)}
            onMouseLeave={() => setMascotHover(false)}
            style={{
              width: "72px",
              height: "72px",
              borderRadius: "50%",
              overflow: "hidden",
              cursor: "pointer",
              boxShadow: mascotHover
                ? "0 10px 36px rgba(220,38,38,0.4),0 4px 12px rgba(0,0,0,0.18)"
                : "0 6px 24px rgba(220,38,38,0.28),0 2px 8px rgba(0,0,0,0.12)",
              transition: "box-shadow 0.18s",
            }}
          >
            <img
              src={
                assistantOpen
                  ? MASCOT_CALM
                  : mascotHover
                  ? MASCOT_HAPPY
                  : MASCOT_CALM
              }
              alt=""
              style={{
                width: "100%",
                height: "100%",
                objectFit: "cover",
                display: "block",
              }}
            />
          </div>
          {activeRulesCount > 0 && !assistantOpen && (
            <div
              style={{
                position: "absolute",
                top: "-2px",
                right: "-2px",
                background: "#2563eb",
                color: "#fff",
                fontSize: "10px",
                fontWeight: 800,
                borderRadius: "999px",
                minWidth: "18px",
                height: "18px",
                padding: "0 4px",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                boxShadow: "0 2px 6px rgba(37,99,235,0.5)",
              }}
            >
              {activeRulesCount}
            </div>
          )}
        </div>
      </div>

      {/* Assistant panel */}
      {assistantOpen && (
        <>
          <div
            style={{
              position: "fixed",
              inset: 0,
              zIndex: 290,
              background: "rgba(0,0,0,0.2)",
            }}
            onClick={() => setAssistantOpen(false)}
          />
          <div
            style={{
              position: "fixed",
              bottom: "108px",
              right: "28px",
              width: "min(920px,calc(100vw - 56px))",
              maxHeight: "calc(100vh - 144px)",
              zIndex: 295,
              background: "#fff",
              borderRadius: "20px",
              border: "1px solid #e4e4e7",
              boxShadow: "0 20px 60px rgba(0,0,0,0.16)",
              display: "flex",
              flexDirection: "column",
              overflow: "hidden",
              animation: "slideUp 0.2s cubic-bezier(0.16,1,0.3,1)",
            }}
            onClick={(e) => e.stopPropagation()}
          >
            <div
              style={{
                display: "flex",
                justifyContent: "space-between",
                alignItems: "center",
                padding: "14px 18px",
                borderBottom: "1px solid #e4e4e7",
                flexShrink: 0,
                background: "#fafafa",
              }}
            >
              <div
                style={{ display: "flex", alignItems: "center", gap: "12px" }}
              >
                <div
                  style={{
                    width: "36px",
                    height: "36px",
                    borderRadius: "50%",
                    overflow: "hidden",
                    flexShrink: 0,
                    boxShadow: "0 3px 10px rgba(220,38,38,0.28)",
                  }}
                >
                  <img
                    src={MASCOT_HAPPY}
                    alt=""
                    style={{
                      width: "100%",
                      height: "100%",
                      objectFit: "cover",
                      display: "block",
                    }}
                  />
                </div>
                <div>
                  <div
                    style={{
                      fontWeight: 800,
                      fontSize: "14px",
                      letterSpacing: "-0.02em",
                    }}
                  >
                    Ассистент
                  </div>
                  <div
                    style={{
                      fontSize: "12px",
                      color: "#71717a",
                      marginTop: "1px",
                    }}
                  >
                    {activeRulesCount > 0 ? (
                      <span style={{ color: "#2563eb", fontWeight: 600 }}>
                        {activeRulesCount} правил активно
                      </span>
                    ) : (
                      "Напишите правило для планировщика"
                    )}
                  </div>
                </div>
              </div>
              <button
                className="btn-small"
                onClick={() => setAssistantOpen(false)}
              >
                Закрыть
              </button>
            </div>
            <div style={{ flex: 1, overflow: "auto", padding: "16px" }}>
              <AssistantPanel
                channels={channels}
                messages={messages}
                rules={rules}
                preferences={preferences}
                onApplyAssistantActions={handleApplyAssistantActions}
                onMessagesChange={setMessages}
                onRulesChange={setRules}
                onPreferencesChange={setPreferences}
              />
            </div>
          </div>
        </>
      )}

      {scheduleDraft && (
        <ScheduleDraftModal
          proposed={scheduleDraft.proposed}
          skipped={scheduleDraft.skipped}
          channels={channels}
          onConfirm={handleConfirmDraft}
          onClose={() => setScheduleDraft(null)}
        />
      )}
    </div>
  );
}

export default function App() {
  return (
    <ToastProvider>
      <AppInner />
    </ToastProvider>
  );
}
